import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { buildApiUrl } from '../utils/api';

const Admin = () => {
  const [foods, setFoods] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [users, setUsers] = useState([]);

  // ---------------- LOAD DATA ----------------
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const foodRes = await axios.get(buildApiUrl('/api/admin/foods'));
      const roomRes = await axios.get(buildApiUrl('/api/admin/rooms'));
      const bookingRes = await axios.get(buildApiUrl('/api/admin/bookings'));
      const userRes = await axios.get(buildApiUrl('/api/admin/users'));

      setFoods(foodRes.data);
      setRooms(roomRes.data);
      setBookings(bookingRes.data.room_bookings);
      setUsers(userRes.data);

    } catch (err) {
      console.error(err);
    }
  };

  // ---------------- ADD FOOD ----------------
  const addFood = async () => {
    await axios.post(buildApiUrl('/api/admin/foods'), {
      name: "New Food",
      price: 1000,
      image: ""
    });
    loadData();
  };

  // ---------------- ADD ROOM ----------------
  const addRoom = async () => {
    await axios.post(buildApiUrl('/api/admin/rooms'), {
      name: "New Room",
      price: 5000
    });
    loadData();
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>ADMIN PANEL</h1>

      {/* FOOD */}
      <h2>🍔 Food</h2>
      <button onClick={addFood}>Add Food</button>
      {foods.map(f => (
        <div key={f.id}>{f.name} - Ksh {f.price}</div>
      ))}

      {/* ROOMS */}
      <h2>🏨 Rooms</h2>
      <button onClick={addRoom}>Add Room</button>
      {rooms.map(r => (
        <div key={r.id}>{r.name} - Ksh {r.price}</div>
      ))}

      {/* BOOKINGS */}
      <h2>📦 Bookings</h2>
      {bookings.map(b => (
        <div key={b.id}>
          {b.room_name} | {b.check_in} → {b.check_out}
        </div>
      ))}

      {/* USERS */}
      <h2>👤 Users</h2>
      {users.map(u => (
        <div key={u.user_id}>
          {u.username} | {u.email}
        </div>
      ))}
    </div>
  );
};

export default Admin;
